#include <stdio.h>
#include <string.h>
#define MAX 1000001
int main() {
    char s[MAX];
    scanf("%s", s);
    int n = strlen(s);
    long long count = 0;
    for (int i = 0; i < n; i++) {
        int a = 0, b = 0, c = 0;
        for (int j = i; j < n; j++) {
            if (s[j] == 'A') a++;
            else if (s[j] == 'B') b++;
            else c++;
            if (a == b && b == c) count++;
        }
    }
    printf("%lld\n", count);
    return 0;
}

