import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        String s = sc.next();
        int n = s.length();
        long count = 0;
        for (int i = 0; i < n; i++) {
            int a = 0, b = 0, c = 0;
            for (int j = i; j < n; j++) {
                if (s.charAt(j) == 'A') a++;
                else if (s.charAt(j) == 'B') b++;
                else c++;
                if (a == b && b == c) count++;
            }
        }
        System.out.println(count);
    }
}

